import React, { useEffect, useState } from "react";
import "./HomePage.css";
import AOS from "aos";
import "aos/dist/aos.css";
import { FaArrowUp, FaBars, FaTimes, FaMoon, FaSun } from "react-icons/fa";

export default function HomePage() {
  const [showScroll, setShowScroll] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [navOpen, setNavOpen] = useState(false);

  useEffect(() => {
    AOS.init({
      duration: 600,   // faster animation
      offset: 80,      // slightly earlier trigger
      easing: 'ease-in-out',
    });


    const handleScroll = () => {
      setShowScroll(window.scrollY > 200);
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
    document.body.classList.toggle("dark-mode");
  };

  const toggleNavbar = () => setNavOpen(!navOpen);

  const scrollToTop = () => window.scrollTo({ top: 0, behavior: "smooth" });

  return (
    <div className="homepage">
      {/* Navbar */}
      <nav className="navbar">
        <div className="logo">Campus<span>Connect</span></div>
        <div className={`nav-links ${navOpen ? "open" : ""}`}>
          <a href="#home" onClick={toggleNavbar}>Home</a>
          <a href="#services" onClick={toggleNavbar}>Services</a>
          <a href="/notes" onClick={toggleNavbar}>Notes</a>
          <a href="/placements" onClick={toggleNavbar}>Placements</a>
          <a href="/internship" onClick={toggleNavbar}>Internships</a>
          <a href="#contact" onClick={toggleNavbar}>Contact</a>
        </div>
        <div className="icons">
          <button className="dark-toggle" onClick={toggleDarkMode}>
            {isDarkMode ? <FaSun /> : <FaMoon />} {isDarkMode ? "Light" : "Dark"}
          </button>
          <button className="hamburger" onClick={toggleNavbar}>
            {navOpen ? <FaTimes /> : <FaBars />}
          </button>
        </div>
      </nav>

      {/* Hero */}
      <section className="hero" id="home">
        <h1 data-aos="fade-down">Welcome to CampusConnect</h1>
        <p data-aos="fade-up">Your all-in-one student hub for academic success.</p>
        <a href="#services" className="cta-btn" data-aos="zoom-in">Join Now</a>
      </section>

      {/* Services */}
      <section className="services" id="services">
        <h2 data-aos="fade-up">Our Core Services</h2>
        <div className="card-container">
          <div className="card" data-aos="zoom-in">
            <span role="img" aria-label="Notes">📚</span>
            <h3>Notes</h3>
          </div>
          <div className="card" data-aos="zoom-in" data-aos-delay="100">
            <span role="img" aria-label="Placements">🎯</span>
            <h3>Placements</h3>
          </div>
          <div className="card" data-aos="zoom-in" data-aos-delay="200">
            <span role="img" aria-label="Internships">💼</span>
            <h3>Internships</h3>
          </div>
          <div className="card" data-aos="zoom-in" data-aos-delay="300">
            <span role="img" aria-label="Events">📅</span>
            <h3>Events</h3>
          </div>
        </div>
      </section>

      {/* About */}
      <section className="about" data-aos="fade-up">
        <h2>Why Choose Us?</h2>
        <p>
          CampusConnect brings you the most organized, easy-to-access student resources, 
          job listings, and learning materials to help you thrive in your academic and career journey.
        </p>
      </section>

      {/* Features */}
      <section className="features" data-aos="fade-up">
        <h2>Top Features</h2>
        <ul>
          <li>✅ Real-time Notifications</li>
          <li>✅ Student Dashboard</li>
          <li>✅ Verified Internship & Placement Listings</li>
          <li>✅ Downloadable Notes</li>
        </ul>
      </section>

      {/* Contact */}
      <section className="contact" id="contact" data-aos="fade-up">
        <h2>Contact Us</h2>
        <p>Email: support@campusconnect.in</p>
        <p>Phone: +91-9876543210</p>
      </section>

      {/* Footer */}
      <footer className="footer" data-aos="fade-up">
        <p>© 2025 CampusConnect. All rights reserved.</p>
      </footer>

      {/* Scroll to Top */}
      {showScroll && (
        <button className="scroll-to-top" onClick={scrollToTop}>
          <FaArrowUp /> Top
        </button>
      )}
    </div>
  );
}
